 const chartReplayTimers = new Map();

 function buildDraftPatchForPrice(currentState = {}, role = '', price = 0) {
 const value = Number(price || 0);
 if (!(value > 0)) return {};
 const currentDraft = normalizeChartTradingDraft(currentState.chartTradingDraft) || {};
 const positionSize = Number(currentState.orderContext?.position?.size || 0) || 0;
 const draft = {
 symbol: String(currentState.symbol || currentDraft.symbol || '').trim().toUpperCase(),
 side: currentDraft.side || '',
 entry: Number(currentDraft.entry || 0) || 0,
 stopLoss: Number(currentDraft.stopLoss || 0) || 0,
 takeProfit: Number(currentDraft.takeProfit || 0) || 0,
 size: Number(currentDraft.size || positionSize || 1) || 1,
 sizeMode: currentDraft.sizeMode || 'contracts',
 orderType: currentDraft.orderType || 'market_order',
 updatedAt: Date.now(),
 };
 if (role === 'entry') draft.entry = value;
 if (role === 'stop') draft.stopLoss = value;
 if (role === 'target') draft.takeProfit = value;
 return { chartTradingDraft: normalizeChartTradingDraft(draft) };
 }

 function nearestDraftRole(draft = null, price = 0) {
 const normalized = normalizeChartTradingDraft(draft);
 if (!normalized || !(Number(price) > 0)) return '';
 return [
 ['entry', normalized.entry],
 ['stop', normalized.stopLoss],
 ['target', normalized.takeProfit],
 ].filter(([, value]) => Number(value) > 0)
 .sort((a, b) => Math.abs(Number(a[1]) - Number(price)) - Math.abs(Number(b[1]) - Number(price)))[0]?.[0] || '';
 }

 async function openChartProtectionPreview(kind = 'stop', preferredSurface = '') {
 const context = resolveChartTradeShortcutContext(preferredSurface);
 const state = context?.state || await getChartState();
 const orderContext = normalizeOrderContext(state.orderContext);
 const draft = normalizeChartTradingDraft(state.chartTradingDraft);
 const triggerPrice = kind === 'target' ? Number(draft?.takeProfit || 0) : Number(draft?.stopLoss || 0);
 const position = orderContext?.position || null;
 if (position && typeof globalThis.openV16ProtectionOrderPreview === 'function') {
 await globalThis.openV16ProtectionOrderPreview(position, kind, triggerPrice > 0 ? { triggerPrice } : {});
 return;
 }
 if (typeof globalThis.openV16OpenOrderEditor === 'function' && orderContext?.linkedOrders?.length) {
 const role = kind === 'target' ? 'take_profit' : 'stop_loss';
 const linked = orderContext.linkedOrders.find(order => String(order.role || '').toLowerCase() === role) || orderContext.linkedOrders[0];
 await globalThis.openV16OpenOrderEditor(linked, triggerPrice > 0 ? { triggerPrice } : {});
 return;
 }
 globalThis.showSystemToast?.('Protection preview needs a position', 'Open the chart from a live position or create a buy/sell preview first.', 'warn', 3200);
 }

 function updateReplayCursorState(currentState = {}, action = 'forward') {
 const replay = normalizeReplayMode(currentState.replayMode);
 const stepMap = { back: -1, forward: 1, back10: -10, forward10: 10 };
 const step = stepMap[action] || 0;
 if (!replay?.active) {
 if (currentState.replaySeed) {
 return { replaySeed: { ...currentState.replaySeed, cursorOffset: action === 'reset' ? 0 : Number(currentState.replaySeed.cursorOffset || 0) + step } };
 }
 return {};
 }
 if (replay.type === 'trade') {
 return {
 replayMode: { ...replay, playing: action === 'reset' ? false : replay.playing },
 replaySeed: currentState.replaySeed ? { ...currentState.replaySeed, cursorOffset: action === 'reset' ? 0 : Number(currentState.replaySeed.cursorOffset || 0) + step } : null,
 };
 }
 const currentIndex = Number.isFinite(Number(replay.cursorIndex)) ? Math.round(Number(replay.cursorIndex)) : null;
 if (currentIndex == null && action !== 'reset') {
 return {
 replayMode: {
 ...replay,
 playing: false,
 cursorIndex: null,
 },
 };
 }
 return {
 replayMode: {
 ...replay,
 playing: action === 'reset' ? false : replay.playing,
 cursorIndex: action === 'reset' ? null : Math.max(0, currentIndex + step),
 },
 };
 }

 function syncReplayPlayback(surface = SURFACE_PREVIEW, state = {}) {
 const replay = normalizeReplayMode(state.replayMode);
 clearInterval(chartReplayTimers.get(surface));
 chartReplayTimers.delete(surface);
 if (!replay?.active || replay.playing !== true) return;
 const timer = setInterval(() => {
 void updateChartState(surface, currentState => updateReplayCursorState(currentState, 'forward'), { forceRender: true });
 }, replay.speedMs || 900);
 chartReplayTimers.set(surface, timer);
 }

 function bindChartTradingSurface(root = document, surface = SURFACE_PREVIEW, state = {}) {
 root.querySelectorAll('[data-ds-lwc-chart]').forEach(chartContainer => {
 let dragRole = '';
 const readPrice = event => globalThis.FWDTradeDeskChartEngine?.readPoint?.(chartContainer, event)?.price || 0;
 const updateDraftAtEvent = async (event, forcedRole = '') => {
 const mode = normalizeChartTradingMode((await getChartState()).chartTradingMode || state.chartTradingMode);
 const price = readPrice(event);
 const currentState = await getChartState();
 const role = forcedRole || (mode === 'adjust' ? nearestDraftRole(currentState.chartTradingDraft, price) : mode);
 if (!['entry', 'stop', 'target'].includes(role)) return;
 await updateChartState(surface, current => buildDraftPatchForPrice(current, role, price), { forceRender: true });
 };
 chartContainer.addEventListener('click', event => {
 const mode = normalizeChartTradingMode(state.chartTradingMode);
 if (!['entry', 'stop', 'target', 'adjust'].includes(mode)) return;
 event.preventDefault();
 void updateDraftAtEvent(event);
 });
 chartContainer.addEventListener('pointerdown', async event => {
 const currentState = await getChartState();
 if (normalizeChartTradingMode(currentState.chartTradingMode) !== 'adjust') return;
 const price = readPrice(event);
 dragRole = nearestDraftRole(currentState.chartTradingDraft, price);
 });
 chartContainer.addEventListener('pointermove', event => {
 if (!dragRole) return;
 event.preventDefault();
 void updateDraftAtEvent(event, dragRole);
 });
 const clearDrag = () => { dragRole = ''; };
 chartContainer.addEventListener('pointerup', clearDrag);
 chartContainer.addEventListener('pointerleave', clearDrag);
 });
 }

